javascript:(function(){function getCleanText(el){const clone=el.cloneNode(true);clone.querySelectorAll('style').forEach(s=>s.remove());clone.querySelectorAll('script, style, .sbai, [style*="display:none"], [style*="display: none"]').forEach(s=>s.remove());return clone.textContent?clone.textContent.trim():''}const selectors=['.wM6W7d span','.lnnVSe[role="option"]','li[role="presentation"] .wM6W7d span','.pcTkSc .wM6W7d span','li[data-attrid="AutocompletePrediction"] .wM6W7d span','.sbsb_a .sbsb_d','li[role="option"]'];let items=[];for(const selector of selectors){const elements=document.querySelectorAll(selector);if(elements.length>0){if(selector==='.wM6W7d span'||selector.includes('.wM6W7d span')){items=Array.from(elements).map(el=>{const text=el.innerHTML?el.innerHTML.replace(/<[^>]*>/g,''):el.textContent||'';return text.trim()}).filter(Boolean)}else{items=Array.from(elements).map(el=>getCleanText(el)).filter(Boolean)}if(items.length>0)break}}items=[...new Set(items)].filter(item=>item&&item.length>0);if(!items.length)return alert('No autocomplete suggestions found. Make sure you have typed something in the Google search box and suggestions are visible.');const text=items.join('\n');navigator.clipboard.writeText(text).then(()=>{alert(`Copied ${items.length} suggestions:\n\n${text.substring(0,200)}${text.length>200?'...':''}`)}).catch(err=>{const textArea=document.createElement('textarea');textArea.value=text;document.body.appendChild(textArea);textArea.select();document.execCommand('copy');document.body.removeChild(textArea);alert(`Copied ${items.length} suggestions (fallback method):\n\n${text.substring(0,200)}${text.length>200?'...':''}`)})})();
